// ========================================
// V5-PRODUCTION: 内部トークン検証 + マルチテナント
// crypto依存排除版 - 外部API委譲
// ========================================

const body = $input.first().json.body || $input.first().json;
const headers = $input.first().json.headers || {};

// 環境変数チェック（フォールバックなし）
const apiUrl = $env.N3_API_URL;
const secret = $env.N8N_INTERNAL_SECRET;

if (!apiUrl) {
  return [{ json: { error: true, message: 'N3_API_URL 環境変数が設定されていません', code: 'CONFIG_ERROR' } }];
}

if (!secret) {
  return [{ json: { error: true, message: 'N8N_INTERNAL_SECRET 環境変数が設定されていません', code: 'CONFIG_ERROR' } }];
}

// 内部トークン検証（外部API経由）
const internalToken = headers['x-n3-signature'] || headers['X-N3-Signature'];
const tokenTimestamp = headers['x-n3-token-timestamp'] || headers['X-N3-Token-Timestamp'];
const userId = body.user_id || 'default';

if (internalToken && tokenTimestamp) {
  try {
    const verifyResponse = await fetch(`${apiUrl}/api/n8n-auth/verify-internal-token`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ userId, timestamp: tokenTimestamp, token: internalToken })
    });
    const verifyResult = await verifyResponse.json();

    if (!verifyResult.valid) {
      return [{ json: { error: true, message: '内部トークンが無効または期限切れです', code: 'INVALID_TOKEN' } }];
    }
  } catch (e) {
    return [{ json: { error: true, message: 'トークン検証APIエラー: ' + e.message, code: 'VERIFY_API_ERROR' } }];
  }
}

const productId = body.product_id;
const marketplace = body.marketplace || 'ebay_us';
const listingData = body.listing_data || {};

if (!productId) return [{ json: { error: true, message: 'product_id が必要です', code: 'MISSING_PARAM' } }];
if (!userId || userId === 'undefined') return [{ json: { error: true, message: 'user_id が必要です', code: 'MISSING_PARAM' } }];

// eBay SiteID マッピング
const SITE_ID_MAP = {
  'ebay_us': 0, 'ebay_uk': 3, 'ebay_de': 77, 'ebay_au': 15,
  'ebay_ca': 2, 'ebay_fr': 71, 'ebay_it': 101, 'ebay_es': 186
};
const siteId = SITE_ID_MAP[marketplace] ?? 0;

return [{ json: { 
  product_id: productId, 
  marketplace: marketplace, 
  user_id: userId, 
  site_id: siteId,
  listing_data: listingData,
  request_timestamp: new Date().toISOString()
} }];

// ========================================
// V5-PRODUCTION: APIキー動的復号
// crypto依存排除版 - 外部API委譲
// ========================================

const request = $node['🔐 内部トークン検証 + 入力検証'].json;
const accountResult = $input.first().json;
const account = Array.isArray(accountResult) ? accountResult[0] : accountResult;

if (!account || !account.api_key_encrypted) {
  return [{ json: { ...request, need_legacy_token: true } }];
}

// 環境変数チェック
const apiUrl = $env.N3_API_URL;
const secret = $env.N8N_INTERNAL_SECRET;

if (!apiUrl || !secret) {
  return [{ json: { ...request, need_legacy_token: true, decrypt_error: '環境変数未設定' } }];
}

// 外部APIで復号
try {
  const decryptResponse = await fetch(`${apiUrl}/api/n8n-auth/decrypt-key`, {
    method: 'POST',
    headers: { 
      'Content-Type': 'application/json',
      'X-N8N-Secret': secret
    },
    body: JSON.stringify({ 
      encryptedValue: account.api_key_encrypted,
      userId: request.user_id
    })
  });

  if (!decryptResponse.ok) {
    return [{ json: { ...request, need_legacy_token: true, decrypt_error: '復号API失敗' } }];
  }

  const { decrypted, error } = await decryptResponse.json();

  if (error || !decrypted) {
    return [{ json: { ...request, need_legacy_token: true, decrypt_error: error || '復号結果なし' } }];
  }

  return [{ json: { ...request, access_token: decrypted, need_legacy_token: false } }];
} catch (e) {
  // 復号失敗時はレガシートークンにフォールバック
  return [{ json: { ...request, need_legacy_token: true, decrypt_error: e.message } }];
}

const request = $node['🔓 APIキー復号'].json;
const tokenResult = $input.first().json;
const token = Array.isArray(tokenResult) ? tokenResult[0] : tokenResult;

if (!token || !token.access_token) {
  return [{ json: { error: true, message: 'eBayトークンが見つかりません（user_id: ' + request.user_id + '）', code: 'TOKEN_NOT_FOUND' } }];
}

return [{ json: { ...request, access_token: token.access_token, need_legacy_token: false } }];

// ========================================
// V5-PRODUCTION: 出品データ準備
// XMLエスケープ追加
// ========================================

// XMLエスケープ関数
function escapeXml(str) {
  if (str === null || str === undefined) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

// CDATA安全化関数
function safeCdata(str) {
  if (!str) return '';
  return String(str).replace(/]]>/g, ']]]]><![CDATA[>');
}

const productResult = $input.first().json;
const product = Array.isArray(productResult) ? productResult[0] : productResult;

// アクセストークン取得（復号済み or レガシー）
let request;
try {
  const legacyCheck = $node['レガシートークン要否'].json;
  if (legacyCheck && legacyCheck.need_legacy_token) {
    request = $node['レガシートークンマージ'].json || $node['🔓 APIキー復号'].json;
  } else {
    request = $node['🔓 APIキー復号'].json;
  }
} catch (e) {
  request = $node['🔓 APIキー復号'].json;
}

if (!product || !product.id) {
  return [{ json: { error: true, message: '商品が見つかりません（user_id権限を確認）', code: 'PRODUCT_NOT_FOUND' } }];
}

if (!request || !request.access_token) {
  return [{ json: { error: true, message: 'eBayトークンが見つかりません', code: 'TOKEN_NOT_FOUND' } }];
}

// XMLエスケープ適用
const title = escapeXml((product.title_en || product.product_name || '').substring(0, 80));
const price = product.listing_price || 99.99;
const quantity = Math.min(product.physical_quantity || 1, 5);
const description = safeCdata(product.description_en || '');
const categoryId = escapeXml(product.ebay_category_id || '888');
const imageUrls = product.image_urls || [];

// ItemSpecifics XMLエスケープ
const itemSpecificsXml = Object.entries(product.item_specifics || {}).map(([name, value]) => 
  `<NameValueList><Name>${escapeXml(name)}</Name><Value>${escapeXml(String(value).substring(0, 65))}</Value></NameValueList>`
).join('');

// PictureURLs XMLエスケープ
const pictureUrlsXml = imageUrls.slice(0, 12).map(url => `<PictureURL>${escapeXml(url)}</PictureURL>`).join('');

return [{ json: {
  product_id: product.id,
  product_updated_at: product.updated_at,
  sku: escapeXml(product.sku),
  title: title,
  price: price,
  quantity: quantity,
  category_id: categoryId,
  access_token: request.access_token,
  marketplace: request.marketplace,
  site_id: request.site_id,
  user_id: request.user_id,
  item_specifics_xml: itemSpecificsXml,
  picture_urls_xml: pictureUrlsXml,
  description: description
} }];

const response = $input.first().json;
const prepareData = $node['📝 出品データ準備'].json;

const responseStr = typeof response === 'string' ? response : JSON.stringify(response);
const ackMatch = responseStr.match(/<Ack>([^<]+)<\/Ack>/);
const itemIdMatch = responseStr.match(/<ItemID>([^<]+)<\/ItemID>/);
const errorMatch = responseStr.match(/<LongMessage>([^<]+)<\/LongMessage>/);

const ack = ackMatch ? ackMatch[1] : 'Unknown';
const itemId = itemIdMatch ? itemIdMatch[1] : null;
const success = ack === 'Success' || ack === 'Warning';

return [{ json: {
  success: success,
  product_id: prepareData.product_id,
  product_updated_at: prepareData.product_updated_at,
  sku: prepareData.sku,
  marketplace: prepareData.marketplace,
  user_id: prepareData.user_id,
  item_id: itemId,
  ack: ack,
  error: success ? null : (errorMatch ? errorMatch[1] : 'eBay APIエラー')
} }];

// 🔐 HMAC SHA256 署名検証 (Empire OS v6)
const crypto = require('crypto');

const signature = $request.headers['x-n3-signature'] || $request.headers['X-N3-Signature'];
const timestamp = $request.headers['x-n3-timestamp'] || $request.headers['X-N3-Timestamp'];
const secret = $env.N8N_HMAC_SECRET;

if (!secret) {
  throw new Error('🚫 N8N_HMAC_SECRET 環境変数が未設定です');
}

if (!signature || !timestamp) {
  throw new Error('🚫 署名またはタイムスタンプが欠落しています');
}

// タイムスタンプ有効期限チェック (5分)
const now = Date.now();
const tsAge = now - parseInt(timestamp);
if (tsAge > 300000 || tsAge < -30000) {
  throw new Error('🚫 タイムスタンプが期限切れまたは不正です');
}

// HMAC検証
const bodyString = JSON.stringify($json);
const computedHmac = crypto
  .createHmac('sha256', secret)
  .update(timestamp + '.' + bodyString)
  .digest('hex');

if (signature !== computedHmac) {
  throw new Error('🚫 HMAC署名検証失敗: 不正なリクエスト');
}

// 検証成功 - 元データをそのまま返す
return [{ json: $json }];
